+fn sqlite_value_matches_like_fast_path(
+    value: &SqliteValue,
+    kind: SqlLikeFastPathKind,
+    literal: &str,
+) -> bool {
+    match value {
+        SqliteValue::Null => false,
+        SqliteValue::Text(text) => sql_like_fast_path_matches(kind, literal, text),
+        SqliteValue::Blob(bytes) => {
+            let text = String::from_utf8_lossy(bytes);
+            sql_like_fast_path_matches(kind, literal, &text)
+        }
+        other => {
+            let text = other.to_text();
+            sql_like_fast_path_matches(kind, literal, &text)
+        }
+    }
+}
